import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import axios from 'axios';
import './ProductDetail.css';

function ProductDetail() {
  const { id } = useParams();
  const [product, setProduct] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchProduct = async () => {
      try {
        const res = await axios.get(`/api/products/${id}`);
        setProduct(res.data);
      } catch (err) {
        console.error('Error fetching product', err);
      } finally {
        setLoading(false);
      }
    };
    fetchProduct();
  }, [id]);

  if (loading) return <div className="loading">Loading...</div>;
  if (!product) return <div className="loading">Product not found.</div>;

  return (
    <div className="product-detail">
      <div className="container">
        <div className="detail-card">
          <div className="detail-image">
            {product.image_url ? (
              <img src={product.image_url} alt={product.name} />
            ) : (
              <div className="product-placeholder">No Image</div>
            )}
          </div>
          <div className="detail-info">
            <h1>{product.name}</h1>
            <p className="detail-price">
              ₹{product.price?.toLocaleString() || 'Price on Request'}
            </p>
            <p className="detail-location">{product.location}</p>
            <p className="detail-description">{product.description}</p>

            <div className="detail-meta">
              <p><strong>Category:</strong> {product.category_name || 'N/A'}</p>
              <p><strong>Supplier:</strong> {product.company_name}</p>
              <p><strong>About Supplier:</strong> {product.company_description}</p>
            </div>

            <div className="detail-actions">
              <Link to="/suppliers" className="btn btn-outline">View Suppliers</Link>
              <Link to="/products" className="btn btn-primary">Back to Products</Link>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default ProductDetail;
